#!/usr/bin/env python3
"""
CI/CD Dependency Installation Script

Installs all requirements from requirements.txt with upgrade flag
for automated deployment pipelines.
"""

import subprocess
import sys
import os
import time
import logging

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    handlers=[
        logging.StreamHandler(sys.stdout),
    ],
)
logger = logging.getLogger(__name__)


def check_pip_available():
    """Verify pip is available in the current environment."""
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "--version"],
            capture_output=True,
            text=True,
            check=True,
        )
        logger.info(f"pip found: {result.stdout.strip()}")
        return True
    except (subprocess.CalledProcessError, FileNotFoundError):
        logger.error("pip is not available in the current Python environment.")
        return False


def upgrade_pip():
    """Upgrade pip itself to the latest version."""
    logger.info("Upgrading pip to latest version...")
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
            capture_output=True,
            text=True,
            check=True,
        )
        logger.info("pip upgraded successfully.")
        return True
    except subprocess.CalledProcessError as e:
        logger.warning(f"Failed to upgrade pip: {e.stderr}")
        return False


def find_requirements_file(filename="requirements.txt"):
    """Locate the requirements file, searching common locations."""
    search_paths = [
        os.path.join(os.getcwd(), filename),
        os.path.join(os.path.dirname(os.path.abspath(__file__)), filename),
        os.path.join(os.getcwd(), "..", filename),
    ]

    # Also check WORKSPACE_DIR env var if set (common in CI/CD)
    workspace = os.environ.get("WORKSPACE_DIR") or os.environ.get("GITHUB_WORKSPACE")
    if workspace:
        search_paths.insert(0, os.path.join(workspace, filename))

    for path in search_paths:
        abs_path = os.path.abspath(path)
        if os.path.isfile(abs_path):
            logger.info(f"Found requirements file: {abs_path}")
            return abs_path

    logger.error(
        f"Requirements file '{filename}' not found. Searched: {search_paths}"
    )
    return None


def validate_requirements_file(filepath):
    """Basic validation of the requirements file."""
    try:
        with open(filepath, "r") as f:
            lines = f.readlines()

        package_count = 0
        for line_num, line in enumerate(lines, 1):
            stripped = line.strip()
            if stripped and not stripped.startswith("#") and not stripped.startswith("-"):
                package_count += 1

        logger.info(f"Requirements file contains ~{package_count} package(s).")
        return package_count > 0
    except (IOError, OSError) as e:
        logger.error(f"Cannot read requirements file: {e}")
        return False


def install_requirements(requirements_path, max_retries=3, retry_delay=5):
    """
    Install requirements using pip with upgrade flag.

    Args:
        requirements_path: Path to requirements.txt
        max_retries: Number of retry attempts on failure
        retry_delay: Seconds to wait between retries
    """
    cmd = [
        sys.executable,
        "-m",
        "pip",
        "install",
        "--upgrade",
        "--no-cache-dir",
        "-r",
        requirements_path,
    ]

    # Add trusted hosts if configured via environment (useful for private PyPI)
    trusted_host = os.environ.get("PIP_TRUSTED_HOST")
    if trusted_host:
        cmd.extend(["--trusted-host", trusted_host])

    # Add extra index URL if configured
    extra_index = os.environ.get("PIP_EXTRA_INDEX_URL")
    if extra_index:
        cmd.extend(["--extra-index-url", extra_index])

    logger.info(f"Running: {' '.join(cmd)}")

    for attempt in range(1, max_retries + 1):
        logger.info(f"Installation attempt {attempt}/{max_retries}...")
        start_time = time.time()

        try:
            result = subprocess.run(
                cmd,
                text=True,
                check=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
            )

            elapsed = time.time() - start_time
            logger.info(f"Installation completed successfully in {elapsed:.1f}s")

            # Log output at debug level or if verbose
            if os.environ.get("CI_VERBOSE", "").lower() in ("1", "true", "yes"):
                for output_line in result.stdout.splitlines():
                    logger.info(f"  pip: {output_line}")

            return True

        except subprocess.CalledProcessError as e:
            elapsed = time.time() - start_time
            logger.error(
                f"Installation attempt {attempt} failed after {elapsed:.1f}s "
                f"(exit code: {e.returncode})"
            )

            if e.stdout:
                # Show last 20 lines of output for debugging
                output_lines = e.stdout.strip().splitlines()
                tail_lines = output_lines[-20:]
                logger.error("Last lines of pip output:")
                for output_line in tail_lines:
                    logger.error(f"  pip: {output_line}")

            if attempt < max_retries:
                logger.info(f"Retrying in {retry_delay} seconds...")
                time.sleep(retry_delay)
                retry_delay *= 2  # Exponential backoff
            else:
                logger.error("All installation attempts failed.")
                return False

    return False


def install_additional_requirements():
    """Install additional requirement files if they exist (e.g., dev, test)."""
    additional_files = [
        "requirements-dev.txt",
        "requirements-test.txt",
        "requirements-ci.txt",
    ]

    for filename in additional_files:
        filepath = find_requirements_file(filename)
        if filepath:
            logger.info(f"Found additional requirements: {filename}")
            if not install_requirements(filepath, max_retries=2):
                logger.warning(
                    f"Failed to install {filename}, continuing anyway..."
                )


def print_installed_packages():
    """Log the list of installed packages for debugging/auditing."""
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "freeze"],
            capture_output=True,
            text=True,
            check=True,
        )
        logger.info("Installed packages:")
        for line in sorted(result.stdout.strip().splitlines()):
            logger.info(f"  {line}")
    except subprocess.CalledProcessError:
        logger.warning("Could not list installed packages.")


def main():
    """Main entry point for CI/CD dependency installation."""
    logger.info("=" * 60)
    logger.info("CI/CD Dependency Installation Script")
    logger.info("=" * 60)

    # Log environment info
    logger.info(f"Python: {sys.version}")
    logger.info(f"Platform: {sys.platform}")
    logger.info(f"Working directory: {os.getcwd()}")

    ci_env = os.environ.get("CI", os.environ.get("CONTINUOUS_INTEGRATION", "unknown"))
    logger.info(f"CI environment: {ci_env}")

    # Step 1: Check pip availability
    if not check_pip_available():
        logger.error("Cannot proceed without pip. Exiting.")
        sys.exit(1)

    # Step 2: Upgrade pip
    upgrade_pip()

    # Step 3: Find requirements file
    requirements_path = find_requirements_file()
    if not requirements_path:
        logger.error("No requirements.txt found. Exiting.")
        sys.exit(1)

    # Step 4: Validate requirements file
    if not validate_requirements_file(requirements_path):
        logger.warning("Requirements file appears empty or invalid.")

    # Step 5: Install requirements
    total_start = time.time()
    success = install_requirements(requirements_path)

    if not success:
        logger.error("Failed to install requirements. Pipeline may be broken.")
        sys.exit(1)

    # Step 6: Install additional requirement files if present
    install_additional_requirements()

    # Step 7: Print summary
    total_elapsed = time.time() - total_start
    logger.info("-" * 60)
    logger.info(f"Total installation time: {total_elapsed:.1f}s")

    if os.environ.get("CI_VERBOSE", "").lower() in ("1", "true", "yes"):
        print_installed_packages()

    logger.info("=" * 60)
    logger.info("Dependency installation completed successfully!")
    logger.info("=" * 60)

    sys.exit(0)


if __name__ == "__main__":
    main()